1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type PolicyContext = { customer: Customer; previousContracts: number };
4	type QuoteInput = PolicyContext & { items: Item[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const LOYALTY_DISCOUNT_RATE = -0.2;
9	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
10	const LOYALTY_THRESHOLD_YEARS = 2;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_BASE = 60;
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const basePremiumForItem = (item: Item): number =>
29	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
30	
31	const isLongStandingCustomer = (customer: Customer): boolean =>
32	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
33	
34	const isHighlyEnchanted = (item: Item): boolean =>
35	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
36	
37	const isCursed = (item: Item): boolean => item.cursed === true;
38	
39	const surcharge = (base: number, applies: boolean, rate: number): number =>
40	  applies ? base * rate : 0;
41	
42	const applyPolicyModifiers = (base: number, ctx: PolicyContext): number =>
43	  base +
44	  surcharge(base, true, FIRST_INSURANCE_SURCHARGE_RATE) +
45	  surcharge(base, isLongStandingCustomer(ctx.customer), LOYALTY_DISCOUNT_RATE) +
46	  surcharge(base, ctx.previousContracts >= 1, FOLLOW_UP_DISCOUNT_RATE);
47	
48	const itemSpecificSurcharges = (item: Item, base: number): number =>
49	  surcharge(base, isCursed(item), CURSED_SURCHARGE_RATE) +
50	  surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
51	
52	const premiumForItem = (item: Item, ctx: PolicyContext): number => {
53	  const base = basePremiumForItem(item);
54	  return applyPolicyModifiers(base, ctx) + itemSpecificSurcharges(item, base);
55	};
56	
57	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
58	
59	const componentGroupBase = (items: Item[]): number => {
60	  const itemBase = basePremiumForItem(items[0]);
61	  if (items.length === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
62	  return items.length * itemBase;
63	};
64	
65	const groupByType = (items: Item[]): Map<string, Item[]> => {
66	  const groups = new Map<string, Item[]>();
67	  for (const item of items) {
68	    const list = groups.get(item.type) ?? [];
69	    list.push(item);
70	    groups.set(item.type, list);
71	  }
72	  return groups;
73	};
74	
75	const componentsTotal = (items: Item[], ctx: PolicyContext): number =>
76	  [...groupByType(items).values()].reduce(
77	    (sum, groupItems) =>
78	      sum + applyPolicyModifiers(componentGroupBase(groupItems), ctx),
79	    0,
80	  );
81	
82	const nonComponentsTotal = (items: Item[], ctx: PolicyContext): number =>
83	  items.reduce((sum, item) => sum + premiumForItem(item, ctx), 0);
84	
85	export const quote = (input: QuoteInput): { premium: number } => {
86	  const components = input.items.filter(isComponent);
87	  const nonComponents = input.items.filter((item) => !isComponent(item));
88	  const itemsTotal =
89	    nonComponentsTotal(nonComponents, input) +
90	    componentsTotal(components, input);
91	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
92	};
93	
94	const DEDUCTIBLE = 100;
95	const CAP_MULTIPLIER = 2;
96	
97	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
98	  sword: 1000,
99	  amulet: 600,
100	  staff: 800,
101	  potion: 400,
102	  rune: 250,
103	  moonstone: 250,
104	};
105	
106	type Damage = { itemType: string; amount: number };
107	type ClaimInput = { items: Item[]; damages: Damage[]; remainingCap?: number };
108	
109	const insuranceValueForItem = (item: Item): number =>
110	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
111	
112	const defaultCap = (items: Item[]): number =>
113	  CAP_MULTIPLIER * items.reduce((sum, item) => sum + insuranceValueForItem(item), 0);
114	
115	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
116	
117	export const claim = (input: ClaimInput): { payout: number; remainingCap: number } => {
118	  const rawPayout = input.damages.reduce((sum, damage) => sum + damagePayout(damage), 0);
119	  const cap = input.remainingCap ?? defaultCap(input.items);
120	  const payout = Math.floor(Math.min(rawPayout, cap));
121	  return { payout, remainingCap: cap - payout };
122	};
